func hexToHSL(hex string) (float64, float64, float64) {
	hex = strings.TrimPrefix(hex, "#")
	if len(hex) < 6 {
		return 0, 0, 0
	}
	r, _ := strconv.ParseInt(hex[0:2], 16, 64)
	g, _ := strconv.ParseInt(hex[2:4], 16, 64)
	b, _ := strconv.ParseInt(hex[4:6], 16, 64)
	rf := float64(r) / 255.0
	gf := float64(g) / 255.0
	bf := float64(b) / 255.0
	max := math.Max(rf, math.Max(gf, bf))
	min := math.Min(rf, math.Min(gf, bf))
	l := (max + min) / 2.0
	if max == min {
		return 0, 0, math.Round(l * 100)
	}
	d := max - min
	var s float64
	if l > 0.5 {
		s = d / (2.0 - max - min)
	} else {
		s = d / (max + min)
	}
	var h float64
	switch max {
	case rf:
		h = (gf - bf) / d
		if gf < bf {
			h += 6
		}
	case gf:
		h = (bf-rf)/d + 2
	case bf:
		h = (rf-gf)/d + 4
	}
	h = h * 60
	return math.Round(h), math.Round(s * 100), math.Round(l * 100)
}

func getDir(ctx context.Context) string {
	if lang, ok := ctx.Value("lang").(string); ok && lang == "ar" {
		return "rtl"
	}
	return "ltr"
}

func GetContentStyle(cfg *config.Config) string {
	if !cfg.Theme.ContentBgColorEnabled {
		return ""
	}
	if cfg.Theme.ContentBgGradientEnabled {
		return fmt.Sprintf("background: linear-gradient(%ddeg, %s, %s);",
			cfg.Theme.ContentBgGradientAngle, cfg.Theme.ContentBgGradientStart, cfg.Theme.ContentBgGradientEnd)
	}
	return fmt.Sprintf("background-color: %s;", cfg.Theme.ContentBgColor)
}

func pageTitleFromPath(path string) string {
	switch {
	case path == "/admin/dashboard" || path == "/":
		return "Dashboard"
	case path == "/admin/site":
		return "Site Settings"
	case path == "/admin/hero":
		return "Hero Section"
	case path == "/admin/sections":
		return "Homepage Sections"
	case path == "/admin/theme":
		return "Theme"
	case path == "/admin/notifications":
		return "Notifications"
	case path == "/admin/facebook_pixel":
		return "Facebook Pixel"
	case path == "/admin/categories":
		return "Categories"
	case path == "/admin/products":
		return "Products"
	case path == "/admin/orders":
		return "Orders"
	case path == "/admin/payment":
		return "Payment Methods"
	case path == "/admin/chat_settings":
		return "Chat Settings"
	case path == "/admin/social_links":
		return "Social Links"
	case path == "/products/new":
		return "New Product"
	default:
		return "Admin"
	}
}

func isItemActive(item config.MenuItem, activePath string) bool {
	return item.Link == activePath
}

